noncompliant:
// Noncompliant: Local variables shadow class members
class Foo
{
  public int myField;
  public int MyProperty { get; set; }

  public void DoSomething()
  {
    int myField = 0;    // Noncompliant
    int MyProperty = 0; // Noncompliant
  }
}

compliant:
// Compliant: Local variables have different names
class Foo
{
  public int myField;
  public int MyProperty { get; set; }

  public void DoSomething()
  {
    int localField = 0;    // Compliant
    int localProperty = 0; // Compliant
  }
}

// Compliant: Using 'this' to access class members
class Foo
{
  public int myField;

  public void DoSomething(int myField)
  {
    this.myField = myField; // Compliant
  }
}
